import React from 'react';

const OurServices: React.FC = () => {
    return (
        <div className="our-services-page">
            <h1>Our Services</h1>
            <div>🚩 Upholstery Cleaning Deep clean sofas, sectionals, loveseats, and chairs. Removes built-up dirt, allergens, and odors — leaving your furniture looking and smelling fresh.</div>
            
        </div>
    );
};

export default OurServices;
